package sn.gestionimmobiliere.backend.reminder.application;
import java.net.URLEncoder;import java.nio.charset.StandardCharsets;import java.time.Clock;import java.util.UUID;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
import sn.gestionimmobiliere.backend.billing.application.BillingService;import sn.gestionimmobiliere.backend.billing.domain.RentCharge;import sn.gestionimmobiliere.backend.lease.application.LeaseService;import sn.gestionimmobiliere.backend.owner.application.OwnerProperties;import sn.gestionimmobiliere.backend.reminder.api.ReminderResponse;import sn.gestionimmobiliere.backend.reminder.domain.Reminder;import sn.gestionimmobiliere.backend.reminder.infrastructure.ReminderRepository;import sn.gestionimmobiliere.backend.tenant.application.TenantService;import sn.gestionimmobiliere.backend.tenant.api.TenantResponse;
@Service public class ReminderService{private final BillingService billing;private final LeaseService leases;private final TenantService tenants;private final ReminderRepository repository;private final OwnerProperties props;private final Clock clock;public ReminderService(BillingService b,LeaseService l,TenantService t,ReminderRepository r,OwnerProperties p,Clock c){billing=b;leases=l;tenants=t;repository=r;props=p;clock=c;}@Transactional public ReminderResponse prepare(UUID chargeId){RentCharge c=billing.entity(chargeId);if(c.getBalance()<=0)throw new IllegalArgumentException("Aucune relance pour une echeance soldee");TenantResponse t=tenants.one(leases.entity(c.getLeaseId()).getTenantId());String message="Bonjour "+t.fullName()+", nous vous rappelons que le loyer de "+c.getPeriodStart()+", d'un solde de "+c.getBalance()+" XOF, etait attendu le "+c.getDueDate()+". Merci de nous contacter pour regulariser votre situation.";Reminder r=repository.saveAndFlush(new Reminder(UUID.randomUUID(),props.organizationId(),chargeId,t.phone(),message,clock.instant()));String number=t.phone().replace("+","");String url="https://wa.me/"+number+"?text="+URLEncoder.encode(message,StandardCharsets.UTF_8);return new ReminderResponse(r.getId(),r.getPhone(),r.getMessage(),url,r.getPreparedAt());}}
